mapper.select:
SELECT src_ip::text AS k, count(*) AS cnt
FROM ${t}

GROUP BY src_ip ORDER BY cnt DESC LIMIT #{limit}

SELECT date_trunc('${iv}', "timestamp"::timestamptz) AS bucket, event_type, count(*) AS cnt
FROM ${t}

     AND "timestamp"::timestamptz >= #{from} 
       AND "timestamp"::timestamptz <  #{to} 
     AND event_type = #{etype} 

GROUP BY bucket, event_type
ORDER BY bucket

SELECT (payload_json::jsonb)->'alert'->>'signature' AS k, count(*) AS cnt
FROM ${t}
WHERE event_type = 'alert' AND (payload_json::jsonb)->'alert'->>'signature' IS NOT NULL
GROUP BY k ORDER BY cnt DESC LIMIT #{limit}

SELECT (payload_json::jsonb)->'alert'->>'category' AS k, count(*) AS cnt
FROM ${t}
WHERE event_type = 'alert' AND (payload_json::jsonb)->'alert'->>'category' IS NOT NULL
GROUP BY k ORDER BY cnt DESC LIMIT #{limit}

SELECT dest_port::text AS k, count(*) AS cnt
FROM ${t}
WHERE dest_port IS NOT NULL
GROUP BY dest_port ORDER BY cnt DESC LIMIT #{limit}

SELECT id, "timestamp", src_ip::text AS src_ip, src_port, dest_ip::text AS dest_ip, dest_port, proto, (payload_json::jsonb)->'alert'->>'signature' AS signature, ((payload_json::jsonb)->'alert'->>'severity')::int AS severity, (payload_json::jsonb)->'alert'->>'category' AS category FROM ${t} WHERE event_type = 'alert' AND ((payload_json::jsonb)->'alert'->>'severity')::int = #{severity} ORDER BY
((payload_json::jsonb)->'alert'->>'severity')::int ASC NULLS LAST, "timestamp" DESC "timestamp" DESC
LIMIT #{limit}

SELECT (payload_json::jsonb)->'alert'->>'signature' AS k, count(*) AS cnt
FROM ${t}
WHERE event_type='alert' AND (src_ip::text = #{ip} OR dest_ip::text = #{ip})
  AND (payload_json::jsonb)->'alert'->>'signature' IS NOT NULL
GROUP BY k ORDER BY cnt DESC LIMIT #{limit}

SELECT dest_port::text AS k, count(*) AS cnt
FROM ${t}
WHERE (src_ip::text = #{ip} OR dest_ip::text = #{ip}) AND dest_port IS NOT NULL
GROUP BY dest_port ORDER BY cnt DESC LIMIT #{limit}

SELECT (payload_json::jsonb)->'alert'->>'severity' AS k, count(*) AS cnt
FROM ${t}
WHERE event_type='alert' AND (payload_json::jsonb)->'alert'->>'signature' = #{sig}
  AND (payload_json::jsonb)->'alert'->>'severity' IS NOT NULL
GROUP BY k ORDER BY k

SELECT src_ip::text AS k, count(*) AS cnt
FROM ${t}
WHERE event_type='alert' AND (payload_json::jsonb)->'alert'->>'signature' = #{sig}
GROUP BY src_ip ORDER BY cnt DESC LIMIT #{limit}

SELECT dest_port::text AS k, count(*) AS cnt
FROM ${t}
WHERE event_type='alert' AND (payload_json::jsonb)->'alert'->>'signature' = #{sig} AND dest_port IS NOT NULL
GROUP BY dest_port ORDER BY cnt DESC LIMIT #{limit}

SELECT to_char(date_trunc('hour', "timestamp"::timestamptz), 'YYYY-MM-DD HH24:MI') AS k, count(*) AS cnt
FROM ${t}
WHERE event_type='alert' AND (payload_json::jsonb)->'alert'->>'signature' = #{sig}
GROUP BY date_trunc('hour', "timestamp"::timestamptz)
ORDER BY date_trunc('hour', "timestamp"::timestamptz)
